import { BrowserRouter, Routes, Route, Link } from "react-router-dom";

function Home() { return <div style={{padding:24}}>Home <Link to="/login">Login</Link></div>; }
function Login() { return <div style={{padding:24}}>Login <Link to="/">Home</Link></div>; }

export default function App() {
    return (
        <BrowserRouter>
            <Routes>
                <Route path="/" element={<Home/>}/>
                <Route path="/login" element={<Login/>}/>
            </Routes>
        </BrowserRouter>
    );
}
